#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[9];
        scanf("%s", s);
        int transitions = 0;
        for (int i = 0; i < 8; i++) {
            if (s[i] != s[(i + 1) % 8]) {
                transitions++;
            }
        }
        if (transitions <= 2) {
            printf("uniform\n");
        } else {
            printf("non-uniform\n");
        }
    }
    return 0;
}

