code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String s = sc.nextLine();
            int transitions = 0;
            for (int i = 0; i < 8; i++) {
                if (s.charAt(i) != s.charAt((i + 1) % 8)) {
                    transitions++;
                }
            }
            if (transitions <= 2) {
                System.out.println("uniform");
            } else {
                System.out.println("non-uniform");
            }
        }
    }
}

